  1→/**
  2→ * Title Extraction
  3→ * Extracts potential recipe title from OCR text using heuristics or semantic embeddings
  4→ */
  5→
  6→import { cosineSimilarity } from "./embeddings";
  7→
  8→export type EmbedFn = (text: string) => Promise<Array<number>>;
  9→
 10→const TITLE_REFERENCE =
 11→  "recipe name, dish title, name of the food, nazwa przepisu, nazwa dania";
 12→const HEADER_REFERENCE =
 13→  "ingredients list, cooking directions, section heading, składniki, przygotowanie, sposób wykonania";
 14→const NOISE_REFERENCE =
 15→  "page number, table of contents, book footer, garbled text";
 16→
 17→/**
 18→ * Measurement units commonly found in ingredient lists
 19→ */
 20→const MEASUREMENT_PATTERNS = [
 21→  "cup",
 22→  "cups",
 23→  "tbsp",
 24→  "tsp",
 25→  "tablespoon",
 26→  "teaspoon",
 27→  "oz",
 28→  "lb",
 29→  "gram",
 30→  "grams",
 31→  "kg",
 32→  "ml",
 33→  "liter",
 34→  "pinch",
 35→  "dash",
 36→  "handful",
 37→];
 38→
 39→function looksLikeIngredient(line: string): boolean {
 40→  const lowerLine = line.toLowerCase();
 41→  return MEASUREMENT_PATTERNS.some((pattern) => lowerLine.includes(pattern));
 42→}
 43→
 44→function startsWithNumber(line: string): boolean {
 45→  return /^\s*\d/.test(line);
 46→}
 47→
 48→function isAllCaps(line: string): boolean {
 49→  const letters = line.replace(/[^a-zA-Z]/g, "");
 50→  return letters.length > 0 && letters === letters.toUpperCase();
 51→}
 52→
 53→function passesHardFilters(text: string): boolean {
 54→  if (text.length < 3 || text.length > 80) return false;
 55→  if (looksLikeIngredient(text)) return false;
 56→  if (startsWithNumber(text)) return false;
 57→  return true;
 58→}
 59→
 60→/**
 61→ * Detect initial burst of short/garbled lines (< 20 chars).
 62→ * Returns the index of the first line >= 20 chars.
 63→ */
 64→function findBurstEnd(lines: Array<{ text: string }>): number {
 65→  let i = 0;
 66→  while (i < lines.length && lines[i].text.length < 20) {
 67→    i++;
 68→  }
 69→  // No long line found — no burst to detect
 70→  if (i >= lines.length) return 0;
 71→  // Need at least 3 consecutive short lines to count as a real burst
 72→  if (i < 3) return 0;
 73→  return i;
 74→}
 75→
 76→function wordCount(text: string): number {
 77→  return text.split(/\s+/).filter((w) => w.length > 0).length;
 78→}
 79→
 80→/**
 81→ * Build candidate strings from lines: single lines plus multi-line joins (2-3 consecutive).
 82→ * Skips initial burst of short lines. Scans all remaining lines. Caps at 25.
 83→ */
 84→function buildCandidates(
 85→  lines: Array<string>
 86→): Array<{ text: string; position: number }> {
 87→  const nonEmptyLines: Array<{ text: string; index: number }> = [];
 88→
 89→  for (let i = 0; i < lines.length; i++) {
 90→    const trimmed = lines[i].trim();
 91→    if (trimmed.length > 0) {
 92→      nonEmptyLines.push({ text: trimmed, index: i });
 93→    }
 94→  }
 95→
 96→  const burstEnd = findBurstEnd(nonEmptyLines);
 97→  const candidates: Array<{ text: string; position: number }> = [];
 98→  const seen = new Set<string>();
 99→
100→  for (let i = burstEnd; i < nonEmptyLines.length; i++) {
101→    const line = nonEmptyLines[i];
102→
103→    // Single line
104→    if (passesHardFilters(line.text)) {
105→      const norm = line.text.toLowerCase();
106→      if (!seen.has(norm)) {
107→        seen.add(norm);
108→        candidates.push({ text: line.text, position: line.index });
109→      }
110→    }
111→
112→    // 2-line join
113→    if (i + 1 < nonEmptyLines.length) {
114→      const joined2 = `${line.text} ${nonEmptyLines[i + 1].text}`;
115→      if (passesHardFilters(joined2)) {
116→        const norm = joined2.toLowerCase();
117→        if (!seen.has(norm)) {
118→          seen.add(norm);
119→          candidates.push({ text: joined2, position: line.index });
120→        }
121→      }
122→    }
123→
124→    // 3-line join
125→    if (i + 2 < nonEmptyLines.length) {
126→      const joined3 = `${line.text} ${nonEmptyLines[i + 1].text} ${nonEmptyLines[i + 2].text}`;
127→      if (passesHardFilters(joined3)) {
128→        const norm = joined3.toLowerCase();
129→        if (!seen.has(norm)) {
130→          seen.add(norm);
131→          candidates.push({ text: joined3, position: line.index });
132→        }
133→      }
134→    }
135→  }
136→
137→  // If more than 25, prioritize ALL_CAPS and short lines
138→  if (candidates.length > 25) {
139→    const prioritized = candidates.slice().sort((a, b) => {
140→      const aAllCaps = isAllCaps(a.text) ? 0 : 1;
141→      const bAllCaps = isAllCaps(b.text) ? 0 : 1;
142→      if (aAllCaps !== bAllCaps) return aAllCaps - bAllCaps;
143→      const aShort = wordCount(a.text) <= 5 ? 0 : 1;
144→      const bShort = wordCount(b.text) <= 5 ? 0 : 1;
145→      return aShort - bShort;
146→    });
147→    return prioritized.slice(0, 25);
148→  }
149→
150→  return candidates;
151→}
152→
153→// Module-level cache for reference embeddings
154→let cachedTitleRefEmbedding: Array<number> | null = null;
155→let cachedHeaderRefEmbedding: Array<number> | null = null;
156→let cachedNoiseRefEmbedding: Array<number> | null = null;
157→
158→export function _resetEmbeddingCacheForTests(): void {
159→  cachedTitleRefEmbedding = null;
160→  cachedHeaderRefEmbedding = null;
161→  cachedNoiseRefEmbedding = null;
162→}
163→
164→export async function extractTitleWithEmbeddings(
165→  text: string,
166→  embed: EmbedFn
167→): Promise<string | undefined> {
168→  if (!text || text.trim().length === 0) {
169→    return undefined;
170→  }
171→
172→  const lines = text.split("\n");
173→  const candidates = buildCandidates(lines);
174→
175→  if (candidates.length === 0) {
176→    return undefined;
177→  }
178→
179→  // Cache reference embeddings
180→  if (!cachedTitleRefEmbedding) {
181→    cachedTitleRefEmbedding = await embed(TITLE_REFERENCE);
182→  }
183→  if (!cachedHeaderRefEmbedding) {
184→    cachedHeaderRefEmbedding = await embed(HEADER_REFERENCE);
185→  }
186→  if (!cachedNoiseRefEmbedding) {
187→    cachedNoiseRefEmbedding = await embed(NOISE_REFERENCE);
188→  }
189→
190→  const scored: Array<{ text: string; position: number; score: number }> = [];
191→
192→  for (const candidate of candidates) {
193→    const embedding = await embed(candidate.text);
194→    const titleSim = cosineSimilarity(embedding, cachedTitleRefEmbedding);
195→    const headerSim = cosineSimilarity(embedding, cachedHeaderRefEmbedding);
196→    const noiseSim = cosineSimilarity(embedding, cachedNoiseRefEmbedding);
197→    const score = titleSim - Math.max(headerSim, noiseSim);
198→
199→    scored.push({ text: candidate.text, position: candidate.position, score });
200→  }
201→
202→  if (scored.length === 0) {
203→    return undefined;
204→  }
205→
206→  const bestScore = Math.max(...scored.map((s) => s.score));
207→  const threshold = Math.max(0.05, bestScore * 0.6);
208→
209→  // Filter candidates above threshold
210→  let selected = scored.filter((s) => s.score >= threshold);
211→
212→  // Deduplicate: if one title is a substring of another, keep the shorter (more focused) one
213→  selected = selected.filter((a) => {
214→    const aLower = a.text.toLowerCase();
215→    return !selected.some(
216→      (b) =>
217→        b !== a &&
218→        aLower.includes(b.text.toLowerCase()) &&
219→        b.text.length < a.text.length
220→    );
221→  });
222→
223→  // Cap at 3, sort by document position
224→  selected.sort((a, b) => a.position - b.position);
225→  selected = selected.slice(0, 3);
226→
227→  if (selected.length === 0) {
228→    return undefined;
229→  }
230→
231→  return selected.map((s) => s.text).join(" + ");
232→}
233→
234→/**
235→ * Extract potential recipe title from OCR text (sync heuristic fallback)
236→ */
237→export function extractTitle(text: string): string | undefined {
238→  if (!text || text.trim().length === 0) {
239→    return undefined;
240→  }
241→
242→  const lines = text.split("\n").map((line) => line.trim());
243→
244→  for (const line of lines) {
245→    if (line.length === 0) continue;
246→    if (line.length < 3 || line.length > 50) continue;
247→    if (looksLikeIngredient(line)) continue;
248→    if (isAllCaps(line)) continue;
249→    if (startsWithNumber(line)) continue;
250→    return line;
251→  }
252→
253→  return undefined;
254→}
