  1→#!/usr/bin/env node
  2→
  3→/**
  4→ * CLI for testing text classifier in Node.js
  5→ * Supports both MiniLM embeddings and TF-IDF for comparison
  6→ * Usage: npx tsx lib/text-classifier/cli.ts <text-file-path> [--method=embeddings|tfidf|both]
  7→ */
  8→
  9→import { pipeline } from "@huggingface/transformers";
 10→import { readFileSync } from "fs";
 11→import { classifyWithEmbeddings, type LabelEmbedding } from "./embeddings";
 12→import type { ClassificationCategory } from "./index.d";
 13→import {
 14→  ALL_CATEGORY_KEYS,
 15→  ALL_CUISINE_KEYS,
 16→  ALL_SEASON_KEYS,
 17→  CATEGORY_LABELS,
 18→  CUISINE_LABELS,
 19→  SEASON_LABELS,
 20→} from "./labels";
 21→import { classifyWithTfIdf } from "./tfidf";
 22→import {
 23→  extractTitle,
 24→  extractTitleWithEmbeddings,
 25→} from "./title-extractor";
 26→
 27→interface TagSuggestion {
 28→  tag: string;
 29→  confidence: number;
 30→  category: ClassificationCategory;
 31→}
 32→
 33→interface EmbeddingOutput {
 34→  data: Float32Array | Array<number>;
 35→}
 36→
 37→interface FeatureEmbedder {
 38→  (
 39→    text: string,
 40→    options: { pooling: "mean"; normalize: true }
 41→  ): Promise<EmbeddingOutput>;
 42→}
 43→
 44→async function embedText(
 45→  embedder: FeatureEmbedder,
 46→  text: string
 47→): Promise<Array<number>> {
 48→  const output = await embedder(text, {
 49→    pooling: "mean",
 50→    normalize: true,
 51→  });
 52→  return Array.from(output.data);
 53→}
 54→
 55→async function computeLabelEmbeddings(
 56→  embedder: FeatureEmbedder
 57→): Promise<Array<LabelEmbedding>> {
 58→  const labelEmbeddings: Array<LabelEmbedding> = [];
 59→
 60→  for (const key of ALL_SEASON_KEYS) {
 61→    const description = SEASON_LABELS[key];
 62→    const embedding = await embedText(embedder, description);
 63→    labelEmbeddings.push({ key, category: "season", embedding });
 64→  }
 65→
 66→  for (const key of ALL_CUISINE_KEYS) {
 67→    const description = CUISINE_LABELS[key];
 68→    const embedding = await embedText(embedder, description);
 69→    labelEmbeddings.push({ key, category: "cuisine", embedding });
 70→  }
 71→
 72→  for (const key of ALL_CATEGORY_KEYS) {
 73→    const description = CATEGORY_LABELS[key];
 74→    const embedding = await embedText(embedder, description);
 75→    labelEmbeddings.push({ key, category: "food-category", embedding });
 76→  }
 77→
 78→  return labelEmbeddings;
 79→}
 80→
 81→async function generateEmbeddingAndClassify(
 82→  embedder: FeatureEmbedder,
 83→  text: string,
 84→  labelEmbeddings: Array<LabelEmbedding>
 85→): Promise<Array<TagSuggestion>> {
 86→  const textEmbedding = await embedText(embedder, text);
 87→  return classifyWithEmbeddings(textEmbedding, labelEmbeddings);
 88→}
 89→
 90→function printResults(
 91→  allSuggestions: Array<TagSuggestion>,
 92→  methodName: string
 93→): void {
 94→  console.log("=".repeat(60));
 95→  console.log(`RESULTS (${methodName})`);
 96→  console.log("=".repeat(60));
 97→  console.log();
 98→
 99→  if (allSuggestions.length === 0) {
100→    console.log("No tags found");
101→  } else {
102→    console.log("Tag Suggestions (confidence scores):");
103→    console.log();
104→
105→    const grouped = {
106→      season: allSuggestions.filter((s) => s.category === "season"),
107→      cuisine: allSuggestions.filter((s) => s.category === "cuisine"),
108→      "food-category": allSuggestions.filter(
109→        (s) => s.category === "food-category"
110→      ),
111→    };
112→
113→    for (const [category, suggestions] of Object.entries(grouped)) {
114→      if (suggestions.length > 0) {
115→        console.log(`  ${category.toUpperCase()}:`);
116→        for (const suggestion of suggestions) {
117→          const confidence = suggestion.confidence.toFixed(3);
118→          const bar = "█".repeat(Math.floor(suggestion.confidence * 50));
119→          console.log(`    ${suggestion.tag.padEnd(20)} ${confidence} ${bar}`);
120→        }
121→        console.log();
122→      }
123→    }
124→  }
125→}
126→
127→/**
128→ * Run TF-IDF classification
129→ */
130→async function runTfIdfClassification(text: string): Promise<void> {
131→  const startTime = Date.now();
132→
133→  console.log("=".repeat(60));
134→  console.log("TEXT CLASSIFIER TEST (TF-IDF)");
135→  console.log("=".repeat(60));
136→  console.log();
137→
138→  console.log("Classifying text with TF-IDF...");
139→  const allSuggestions = classifyWithTfIdf(text);
140→  allSuggestions.sort((a, b) => b.confidence - a.confidence);
141→
142→  console.log();
143→  printResults(allSuggestions, "TF-IDF");
144→
145→  const totalTime = Date.now() - startTime;
146→  console.log(
147→    `Processing time: ${totalTime}ms (${(totalTime / 1000).toFixed(1)}s)`
148→  );
149→  console.log();
150→}
151→
152→async function loadEmbedder(): Promise<FeatureEmbedder> {
153→  console.log("Loading MiniLM embedding model (this may take a moment)...");
154→  const embedder = (await pipeline(
155→    "feature-extraction",
156→    "Xenova/all-MiniLM-L6-v2",
157→    {
158→      progress_callback: (progress: {
159→        status?: string;
160→        loaded?: number;
161→        total?: number;
162→      }) => {
163→        if (
164→          progress.status === "progress" &&
165→          progress.loaded &&
166→          progress.total
167→        ) {
168→          const percent = Math.round((progress.loaded / progress.total) * 100);
169→          process.stdout.write(`\rDownloading: ${percent}%`);
170→        } else if (progress.status === "done") {
171→          process.stdout.write("\rDownload complete!\n");
172→        }
173→      },
174→    }
175→  )) as unknown as FeatureEmbedder;
176→
177→  console.log("Model loaded!");
178→  console.log();
179→  return embedder;
180→}
181→
182→/**
183→ * Run embeddings classification
184→ */
185→async function runEmbeddingsClassification(
186→  text: string,
187→  existingEmbedder?: FeatureEmbedder
188→): Promise<void> {
189→  const startTime = Date.now();
190→
191→  console.log("=".repeat(60));
192→  console.log("TEXT CLASSIFIER TEST (MiniLM Embeddings)");
193→  console.log("=".repeat(60));
194→  console.log();
195→
196→  const embedder = existingEmbedder ?? (await loadEmbedder());
197→
198→  // Extract semantic title
199→  const embed = async (t: string): Promise<Array<number>> =>
200→    embedText(embedder, t);
201→  console.log("Extracting semantic title...");
202→  const semanticTitle = await extractTitleWithEmbeddings(text, embed);
203→  console.log(`Semantic Title: ${semanticTitle || "(none found)"}`);
204→  console.log();
205→
206→  console.log("Computing label embeddings...");
207→  const labelEmbeddings = await computeLabelEmbeddings(embedder);
208→  console.log(`Cached ${labelEmbeddings.length} label embeddings`);
209→  console.log();
210→
211→  console.log("Classifying text...");
212→  const allSuggestions = await generateEmbeddingAndClassify(
213→    embedder,
214→    text,
215→    labelEmbeddings
216→  );
217→
218→  console.log();
219→  printResults(allSuggestions, "MiniLM Embeddings");
220→
221→  const totalTime = Date.now() - startTime;
222→  console.log(
223→    `Processing time: ${totalTime}ms (${(totalTime / 1000).toFixed(1)}s)`
224→  );
225→  console.log();
226→}
227→
228→/**
229→ * Run both methods for comparison
230→ */
231→async function runBothMethods(text: string): Promise<void> {
232→  console.log("=".repeat(60));
233→  console.log("TEXT CLASSIFIER COMPARISON TEST");
234→  console.log("=".repeat(60));
235→  console.log();
236→
237→  // Extract heuristic title
238→  console.log("Extracting title (heuristic)...");
239→  const heuristicTitle = extractTitle(text);
240→  console.log(`Heuristic Title: ${heuristicTitle || "(none found)"}`);
241→
242→  // Extract semantic title
243→  const embedder = await loadEmbedder();
244→  const embed = async (t: string): Promise<Array<number>> =>
245→    embedText(embedder, t);
246→  console.log("Extracting title (semantic)...");
247→  const semanticTitle = await extractTitleWithEmbeddings(text, embed);
248→  console.log(`Semantic Title:  ${semanticTitle || "(none found)"}`);
249→  console.log();
250→  console.log();
251→
252→  // Run TF-IDF
253→  await runTfIdfClassification(text);
254→
255→  console.log();
256→  console.log();
257→
258→  // Run Embeddings (reuse already-loaded embedder)
259→  await runEmbeddingsClassification(text, embedder);
260→}
261→
262→/**
263→ * Main entry point
264→ */
265→async function main(): Promise<void> {
266→  const args = process.argv.slice(2);
267→
268→  if (args.length === 0) {
269→    console.error(
270→      "Usage: npx tsx lib/text-classifier/cli.ts <text-file-path> [--method=embeddings|tfidf|both]"
271→    );
272→    console.error("");
273→    console.error("Examples:");
274→    console.error(
275→      "  npx tsx lib/text-classifier/cli.ts recipe.txt --method=embeddings"
276→    );
277→    console.error(
278→      "  npx tsx lib/text-classifier/cli.ts recipe.txt --method=tfidf"
279→    );
280→    console.error(
281→      "  npx tsx lib/text-classifier/cli.ts recipe.txt --method=both"
282→    );
283→    console.error(
284→      "  npx tsx lib/text-classifier/cli.ts recipe.txt  (defaults to both)"
285→    );
286→    process.exit(1);
287→  }
288→
289→  const filePath = args[0];
290→  const methodArg = args.find((arg) => arg.startsWith("--method="));
291→  const method = methodArg ? methodArg.split("=")[1] : "both";
292→
293→  if (!["embeddings", "tfidf", "both"].includes(method)) {
294→    console.error(
295→      `Error: Invalid method '${method}'. Must be 'embeddings', 'tfidf', or 'both'`
296→    );
297→    process.exit(1);
298→  }
299→
300→  try {
301→    const text = readFileSync(filePath, "utf-8");
302→
303→    if (!text.trim()) {
304→      console.error(`Error: File '${filePath}' is empty`);
305→      process.exit(1);
306→    }
307→
308→    if (method === "both") {
309→      await runBothMethods(text);
310→    } else if (method === "tfidf") {
311→      console.log("Extracting title...");
312→      const title = extractTitle(text);
313→      console.log(`Title: ${title || "(none found)"}`);
314→      console.log();
315→      console.log();
316→      await runTfIdfClassification(text);
317→    } else {
318→      // embeddings
319→      await runEmbeddingsClassification(text);
320→    }
321→  } catch (error) {
322→    if ((error as NodeJS.ErrnoException).code === "ENOENT") {
323→      console.error(`Error: File '${filePath}' not found`);
324→      process.exit(1);
325→    }
326→    console.error("Error:", error);
327→    process.exit(1);
328→  }
329→}
330→
331→main().catch((error) => {
332→  console.error("Fatal error:", error);
333→  process.exit(1);
334→});
