  1→/**
  2→ * Native Text Classifier
  3→ * Supports both MiniLM embeddings (via TextEmbeddingsModule) and TF-IDF
  4→ */
  5→
  6→import {
  7→  ALL_MINILM_L6_V2,
  8→  TextEmbeddingsModule,
  9→} from "react-native-executorch";
 10→import { classifyWithEmbeddings, type LabelEmbedding } from "./embeddings";
 11→import type {
 12→  ClassificationMethod,
 13→  ClassificationResult,
 14→  TagSuggestion,
 15→} from "./index.d";
 16→import {
 17→  ALL_CATEGORY_KEYS,
 18→  ALL_CUISINE_KEYS,
 19→  ALL_SEASON_KEYS,
 20→  CATEGORY_LABELS,
 21→  CUISINE_LABELS,
 22→  SEASON_LABELS,
 23→} from "./labels";
 24→import { classifyWithTfIdf } from "./tfidf";
 25→import {
 26→  extractTitle,
 27→  extractTitleWithEmbeddings,
 28→} from "./title-extractor";
 29→
 30→/**
 31→ * Singleton pattern for model and label embeddings
 32→ */
 33→class EmbeddingsManager {
 34→  private static instance: TextEmbeddingsModule | null = null;
 35→  private static labelEmbeddings: Array<LabelEmbedding> | null = null;
 36→  private static isInitializing = false;
 37→
 38→  static async initialize(): Promise<void> {
 39→    if (this.instance && this.labelEmbeddings) {
 40→      return; // Already initialized
 41→    }
 42→
 43→    if (this.isInitializing) {
 44→      // Wait for ongoing initialization
 45→      await new Promise((resolve) => setTimeout(resolve, 100));
 46→      return this.initialize();
 47→    }
 48→
 49→    this.isInitializing = true;
 50→
 51→    try {
 52→      console.log("[Text Classifier] Initializing MiniLM model...");
 53→
 54→      // Create and load the model
 55→      this.instance = new TextEmbeddingsModule();
 56→      await this.instance.load({
 57→        modelSource: ALL_MINILM_L6_V2.modelSource,
 58→        tokenizerSource: ALL_MINILM_L6_V2.tokenizerSource,
 59→      });
 60→
 61→      console.log("[Text Classifier] Computing label embeddings...");
 62→
 63→      // Compute embeddings for all labels
 64→      const embeddings: Array<LabelEmbedding> = [];
 65→
 66→      for (const key of ALL_SEASON_KEYS) {
 67→        const description = SEASON_LABELS[key];
 68→        const embeddingRaw = await this.instance.forward(description);
 69→        const embedding = Array.from(embeddingRaw);
 70→        embeddings.push({ key, category: "season", embedding });
 71→      }
 72→
 73→      for (const key of ALL_CUISINE_KEYS) {
 74→        const description = CUISINE_LABELS[key];
 75→        const embeddingRaw = await this.instance.forward(description);
 76→        const embedding = Array.from(embeddingRaw);
 77→        embeddings.push({ key, category: "cuisine", embedding });
 78→      }
 79→
 80→      for (const key of ALL_CATEGORY_KEYS) {
 81→        const description = CATEGORY_LABELS[key];
 82→        const embeddingRaw = await this.instance.forward(description);
 83→        const embedding = Array.from(embeddingRaw);
 84→        embeddings.push({ key, category: "food-category", embedding });
 85→      }
 86→
 87→      this.labelEmbeddings = embeddings;
 88→      console.log(
 89→        `[Text Classifier] Initialized with ${embeddings.length} label embeddings`
 90→      );
 91→    } finally {
 92→      this.isInitializing = false;
 93→    }
 94→  }
 95→
 96→  static async forward(text: string): Promise<Array<number>> {
 97→    await this.initialize();
 98→
 99→    if (!this.instance) {
100→      throw new Error("Failed to initialize embeddings");
101→    }
102→
103→    const raw = await this.instance.forward(text);
104→    return Array.from(raw);
105→  }
106→
107→  static async classify(text: string): Promise<Array<TagSuggestion>> {
108→    await this.initialize();
109→
110→    if (!this.instance || !this.labelEmbeddings) {
111→      throw new Error("Failed to initialize embeddings");
112→    }
113→
114→    // Get text embedding
115→    const textEmbeddingRaw = await this.instance.forward(text);
116→    const textEmbedding = Array.from(textEmbeddingRaw);
117→
118→    // Use shared classification function
119→    return classifyWithEmbeddings(textEmbedding, this.labelEmbeddings);
120→  }
121→}
