  1→/**
  2→ * Web Text Classifier
  3→ * Supports both MiniLM embeddings (via worker) and TF-IDF
  4→ */
  5→
  6→import type {
  7→  ClassificationMethod,
  8→  ClassificationResult,
  9→  TagSuggestion,
 10→} from "./index.d";
 11→import { classifyWithTfIdf } from "./tfidf";
 12→import { extractTitle } from "./title-extractor";
 13→
 14→// @ts-expect-error - Metro transformer bundles this as a string
 15→import workerCode from "./worker";
 16→
 17→interface ClassificationResponse {
 18→  type: "classification-result";
 19→  requestId: string;
 20→  success: boolean;
 21→  title?: string;
 22→  suggestions?: Array<TagSuggestion>;
 23→  error?: string;
 24→  processingTimeMs?: number;
 25→}
 26→
 27→interface ProgressMessage {
 28→  type: "progress";
 29→  requestId: string;
 30→  phase: string;
 31→  message: string;
 32→}
 33→
 34→let worker: Worker | null = null;
 35→let workerReady = false;
 36→let nextRequestId = 0;
 37→
 38→const pendingRequests = new Map<
 39→  string,
 40→  {
 41→    resolve: (result: ClassificationResult) => void;
 42→    reject: (error: Error) => void;
 43→  }
 44→>();
 45→
 46→/**
 47→ * Check if Web Workers are supported
 48→ */
 49→function isWorkerSupported(): boolean {
 50→  return typeof Worker !== "undefined" && typeof window !== "undefined";
 51→}
 52→
 53→/**
 54→ * Initialize Classification Web Worker
 55→ */
 56→function initializeWorker(): void {
 57→  if (!isWorkerSupported() || worker) {
 58→    return;
 59→  }
 60→
 61→  try {
 62→    const blob = new Blob([workerCode as unknown as string], {
 63→      type: "application/javascript",
 64→    });
 65→    const workerUrl = URL.createObjectURL(blob);
 66→    worker = new Worker(workerUrl);
 67→
 68→    worker.onmessage = (event: MessageEvent) => {
 69→      const message = event.data;
 70→
 71→      if (message.type === "classification-result") {
 72→        const response = message as ClassificationResponse;
 73→        const pending = pendingRequests.get(response.requestId);
 74→        if (pending) {
 75→          pendingRequests.delete(response.requestId);
 76→          if (response.success && response.suggestions) {
 77→            pending.resolve({
 78→              title: response.title,
 79→              suggestions: response.suggestions,
 80→              processingTimeMs: response.processingTimeMs || 0,
 81→            });
 82→          } else {
 83→            pending.reject(
 84→              new Error(response.error || "Classification failed")
 85→            );
 86→          }
 87→        }
 88→      } else if (message.type === "progress") {
 89→        const progress = message as ProgressMessage;
 90→        console.log(`[Text Classifier] ${progress.phase}: ${progress.message}`);
 91→      }
 92→    };
 93→
 94→    worker.onerror = (error: ErrorEvent) => {
 95→      console.error("[Text Classifier] Worker error:", error);
 96→      worker = null;
 97→      workerReady = false;
 98→    };
 99→
100→    workerReady = true;
101→    console.log("[Text Classifier] Worker initialized successfully");
102→  } catch (error) {
103→    console.warn(
104→      "[Text Classifier] Failed to initialize worker, classification will not be available:",
105→      error
106→    );
107→    worker = null;
108→    workerReady = false;
109→  }
110→}
111→
112→/**
113→ * Classify text using the worker
114→ */
115→async function classifyWithWorker(text: string): Promise<ClassificationResult> {
116→  if (!worker || !workerReady) {
117→    throw new Error("Worker not initialized");
118→  }
119→
120→  const requestId = `req_${nextRequestId++}`;
121→
122→  return new Promise((resolve, reject) => {
123→    pendingRequests.set(requestId, { resolve, reject });
124→
125→    worker!.postMessage({
126→      type: "classify",
127→      requestId,
128→      text,
129→    });
130→
131→    // Timeout after 30 seconds
132→    setTimeout(() => {
133→      if (pendingRequests.has(requestId)) {
134→        pendingRequests.delete(requestId);
135→        reject(new Error("Classification timeout"));
136→      }
137→    }, 30000);
138→  });
139→}
