  1→import {
  2→  extractTitle,
  3→  extractTitleWithEmbeddings,
  4→  _resetEmbeddingCacheForTests,
  5→} from "../title-extractor";
  6→
  7→/**
  8→ * Creates a mock embed function that returns predictable vectors.
  9→ * Words matching titleWords get a vector pointing "toward titles",
 10→ * words matching headerWords get a vector pointing "toward headers",
 11→ * and everything else gets a neutral vector.
 12→ */
 13→function createMockEmbed(
 14→  titleWords: Array<string>,
 15→  headerWords: Array<string>
 16→): (text: string) => Promise<Array<number>> {
 17→  // Reference phrases from the module
 18→  const TITLE_REF =
 19→    "recipe name, dish title, name of the food, nazwa przepisu, nazwa dania";
 20→  const HEADER_REF =
 21→    "ingredients list, cooking directions, section heading, składniki, przygotowanie, sposób wykonania";
 22→  const NOISE_REF =
 23→    "page number, table of contents, book footer, garbled text";
 24→
 25→  return async (text: string): Promise<Array<number>> => {
 26→    const lower = text.toLowerCase();
 27→
 28→    // Title reference → unit vector in dimension 0
 29→    if (lower === TITLE_REF.toLowerCase()) {
 30→      return [1, 0, 0];
 31→    }
 32→    // Header reference → unit vector in dimension 1
 33→    if (lower === HEADER_REF.toLowerCase()) {
 34→      return [0, 1, 0];
 35→    }
 36→    // Noise reference → unit vector in dimension 2 (orthogonal)
 37→    if (lower === NOISE_REF.toLowerCase()) {
 38→      return [0, 0, 1];
 39→    }
 40→
 41→    // Check if text contains title-like words → high cosine with title ref
 42→    const isTitle = titleWords.some((w) => lower.includes(w.toLowerCase()));
 43→    // Check if text contains header-like words → high cosine with header ref
 44→    const isHeader = headerWords.some((w) => lower.includes(w.toLowerCase()));
 45→
 46→    if (isTitle && !isHeader) {
 47→      return [0.9, 0.1, 0]; // High title similarity, low header similarity
 48→    }
 49→    if (isHeader && !isTitle) {
 50→      return [0.1, 0.9, 0]; // Low title similarity, high header similarity
 51→    }
 52→    if (isTitle && isHeader) {
 53→      return [0.5, 0.5, 0]; // Ambiguous
 54→    }
 55→    // Neutral
 56→    return [0.3, 0.3, 0.7];
 57→  };
 58→}
