 1→/**
 2→ * MiniLM Embeddings Text Classification
 3→ * Shared utilities for embedding-based classification across platforms
 4→ */
 5→
 6→import type { ClassificationCategory } from "./index.d";
 7→
 8→export interface LabelEmbedding {
 9→  key: string;
10→  category: ClassificationCategory;
11→  embedding: Array<number>;
12→}
13→
14→export interface EmbeddingSuggestion {
15→  tag: `#${string}`;
16→  confidence: number;
17→  category: ClassificationCategory;
18→}
19→
20→/**
21→ * Similarity threshold for embeddings classification
22→ * Embeddings with similarity >= this value are considered matches
23→ */
24→export const SIMILARITY_THRESHOLD = 0.453;
25→
26→/**
27→ * Compute cosine similarity between two normalized embeddings
28→ * Since MiniLM embeddings are normalized, this is just the dot product
29→ */
30→export function cosineSimilarity(
31→  embedding1: Array<number>,
32→  embedding2: Array<number>
33→): number {
34→  let dotProduct = 0;
35→  for (let i = 0; i < embedding1.length; i++) {
36→    dotProduct += embedding1[i] * embedding2[i];
37→  }
38→  return dotProduct;
39→}
40→
41→/**
42→ * Classify text using precomputed label embeddings
43→ */
44→export function classifyWithEmbeddings(
45→  textEmbedding: Array<number>,
46→  labelEmbeddings: Array<LabelEmbedding>
47→): Array<EmbeddingSuggestion> {
48→  const suggestions: Array<EmbeddingSuggestion> = [];
49→
50→  for (const label of labelEmbeddings) {
51→    const similarity = cosineSimilarity(textEmbedding, label.embedding);
52→
53→    if (similarity >= SIMILARITY_THRESHOLD) {
54→      suggestions.push({
55→        tag: `#${label.key}` as `#${string}`,
56→        confidence: similarity,
57→        category: label.category,
58→      });
59→    }
60→  }
61→
62→  // Sort by confidence (descending)
63→  suggestions.sort((a, b) => b.confidence - a.confidence);
64→
65→  return suggestions;
66→}
