31→      "feature-extraction",
32→      "Xenova/all-MiniLM-L6-v2"
33→    )) as unknown as FeatureEmbedder;
34→  }
35→  return cachedEmbedder;
36→}
37→
38→async function embedText(text: string): Promise<Array<number>> {
39→  const embedder = await getEmbedder();
40→  const output = await embedder(text, { pooling: "mean", normalize: true });
41→  return Array.from(output.data);
42→}
43→
44→async function main(): Promise<void> {
45→  const filePath = process.argv[2];
46→  if (!filePath) {
47→    console.error("Usage: npx tsx tools/title-loop/extract-title.ts <text-file>");
48→    process.exit(1);
49→  }
50→
51→  const text = readFileSync(filePath, "utf-8");
52→  if (!text.trim()) {
53→    process.stdout.write("");
54→    process.exit(0);
55→  }
56→
57→  const title = await extractTitleWithEmbeddings(text, embedText);
58→  process.stdout.write(title ?? "");
59→}
60→
61→main().catch((err) => {
62→  console.error(err);
63→  process.exit(1);
64→});
